import{_ as a,c as e,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Monitoramento e Solução de Problemas: Análise de Logs de Solicitação | Antigravity-Manager","description":"Aprenda o monitoramento e solução de problemas do Proxy Monitor nas Antigravity Tools. Por meio de logs de solicitação, filtragem e recursos de restauração de detalhes, localize problemas de erro 401/429/5xx e interrupções de streaming.","frontmatter":{"title":"Monitoramento e Solução de Problemas: Análise de Logs de Solicitação | Antigravity-Manager","sidebarTitle":"Verificação de erros de log de solicitação","subtitle":"Monitoramento e Solução de Problemas: Análise de Logs de Solicitação","description":"Aprenda o monitoramento e solução de problemas do Proxy Monitor nas Antigravity Tools. Por meio de logs de solicitação, filtragem e recursos de restauração de detalhes, localize problemas de erro 401/429/5xx e interrupções de streaming.","tags":["avançado","monitoramento","solução de problemas","Proxy","logs"],"prerequisite":["start-proxy-and-first-client","start-first-run-data","advanced-config"],"order":6},"headers":[],"relativePath":"pt/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md","filePath":"pt/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"}'),i={name:"pt/lbjlaq/Antigravity-Manager/advanced/monitoring/index.md"};function s(d,o,n,l,c,p){return r(),e("div",null,[...o[0]||(o[0]=[t(`<h1 id="proxy-monitor-logs-de-solicitacao-filtragem-restauracao-de-detalhes-e-exportacao" tabindex="-1">Proxy Monitor: Logs de Solicitação, Filtragem, Restauração de Detalhes e Exportação <a class="header-anchor" href="#proxy-monitor-logs-de-solicitacao-filtragem-restauracao-de-detalhes-e-exportacao" aria-label="Permalink to &quot;Proxy Monitor: Logs de Solicitação, Filtragem, Restauração de Detalhes e Exportação&quot;">​</a></h1><p>Você já iniciou o proxy reverso local, mas assim que aparecem 401/429/500, interrupções de streaming, ou &quot;de repente mudou de conta/modelo&quot;, a solução de problemas facilmente se torna cega.</p><p>Esta aula foca em apenas uma coisa: usar o <strong>Proxy Monitor</strong> para restaurar cada chamada em &quot;evidências revisitáveis&quot;, permitindo que você saiba de onde a solicitação veio, para qual endpoint foi, qual conta foi usada, se o modelo foi mapeado, e aproximadamente quanto Token foi consumido.</p><h2 id="o-que-voce-podera-fazer-apos-concluir" tabindex="-1">O que você poderá fazer após concluir <a class="header-anchor" href="#o-que-voce-podera-fazer-apos-concluir" aria-label="Permalink to &quot;O que você poderá fazer após concluir&quot;">​</a></h2><ul><li>Abrir/pausar a gravação na página <code>/monitor</code> e entender se isso afetará o Token Stats</li><li>Usar caixa de busca, filtragem rápida e filtragem de conta para localizar rapidamente um registro de solicitação</li><li>No popup de detalhes, ver e copiar payloads de Request/Response para analisar falhas</li><li>Saber onde o Proxy Monitor grava dados (<code>proxy_logs.db</code>) e o comportamento de limpeza</li><li>Entender a capacidade real atual de &quot;exportar logs&quot; (GUI vs comando de backend)</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">​</a></h2><ul><li>Você só vê &quot;falha na chamada/timeout&quot;, mas não sabe se a falha foi no upstream, no proxy ou na configuração do cliente</li><li>Você suspeita que acionou o mapeamento de modelo ou rotação de conta, mas não tem cadeia de evidências</li><li>Você quer revisitar o payload completo de uma solicitação (especialmente streaming/Thinking), mas não vê nos logs</li></ul><h2 id="quando-usar-esta-estrategia" tabindex="-1">Quando usar esta estratégia <a class="header-anchor" href="#quando-usar-esta-estrategia" aria-label="Permalink to &quot;Quando usar esta estratégia&quot;">​</a></h2><ul><li>Você precisa solucionar problemas: falha de autenticação 401, limitação de taxa 429, erro upstream 5xx, interrupção de streaming</li><li>Você quer confirmar: qual conta foi realmente usada em uma solicitação específica (<code>X-Account-Email</code>)</li><li>Você está trabalhando em estratégias de roteamento de modelo e quer verificar &quot;nome do modelo do cliente -&gt; nome do modelo mapeado&quot;</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação antes de começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação antes de começar&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Pré-requisitos</p><p>O Proxy Monitor registra &quot;solicitações recebidas pelo serviço de proxy reverso&quot;. Então você precisa primeiro ter funcionado:</p><ul><li>Serviço de proxy reverso iniciado e capaz de acessar <code>/healthz</code></li><li>Você sabe a URL base e porta do proxy reverso atual</li></ul><p>Se ainda não funcionou, primeiro veja <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Iniciar proxy reverso local e conectar o primeiro cliente</a></strong>.</p></div><h2 id="o-que-e-proxy-monitor" tabindex="-1">O que é Proxy Monitor? <a class="header-anchor" href="#o-que-e-proxy-monitor" aria-label="Permalink to &quot;O que é Proxy Monitor?&quot;">​</a></h2><p><strong>Proxy Monitor</strong> é o &quot;painel de logs de solicitação&quot; integrado nas Antigravity Tools. Cada vez que uma solicitação entra no proxy reverso local, ele registra hora, caminho, código de status, duração, modelo e protocolo, e tenta extrair o uso de Token da resposta; você também pode clicar em um único registro para ver os payloads de solicitação e resposta, usando-o para analisar causas de falha e resultados de seleção de rota/conta.</p><div class="info custom-block"><p class="custom-block-title">Local de gravação de dados</p><p>Os logs do Proxy Monitor são gravados no SQLite no diretório de dados: <code>proxy_logs.db</code>. Como encontrar o diretório de dados e como fazer backup, sugiro revisar primeiro <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/start/first-run-data/">Primeira execução: diretório de dados, logs, bandeja e inicialização automática</a></strong>.</p></div><h2 id="ideia-central-6-campos-que-voce-precisa-monitorar" tabindex="-1">Ideia central: 6 campos que você precisa monitorar <a class="header-anchor" href="#ideia-central-6-campos-que-voce-precisa-monitorar" aria-label="Permalink to &quot;Ideia central: 6 campos que você precisa monitorar&quot;">​</a></h2><p>Em um registro do Proxy Monitor (struct do backend <code>ProxyRequestLog</code>), os mais úteis são estes campos:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Com que pergunta você o usa</th></tr></thead><tbody><tr><td><code>status</code></td><td>Esta solicitação foi bem-sucedida ou falhou (200-399 vs outros)</td></tr><tr><td><code>url</code> / <code>method</code></td><td>Qual endpoint você realmente atingiu (por exemplo <code>/v1/messages</code>, <code>/v1/chat/completions</code>)</td></tr><tr><td><code>protocol</code></td><td>É qual protocolo: OpenAI / Claude(Anthropic) / Gemini</td></tr><tr><td><code>account_email</code></td><td>Qual conta esta solicitação finalmente usou (do cabeçalho de resposta <code>X-Account-Email</code>)</td></tr><tr><td><code>model</code> / <code>mapped_model</code></td><td>O nome do modelo solicitado pelo cliente foi &quot;roteado/mapeado&quot; para outro modelo</td></tr><tr><td><code>input_tokens</code> / <code>output_tokens</code></td><td>Uso de Token desta solicitação (só se puder extrair)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Primeiro use &quot;resumo&quot;, então clique &quot;detalhes&quot; quando necessário</p><p>A página da lista só mostra resumo (sem corpo request/response), clicar em um registro carregará detalhes completos do backend, evitando carregar muitos campos grandes de uma vez.</p></div><h2 id="siga-me-use-uma-chamada-para-completar-o-ciclo-de-monitoramento" tabindex="-1">Siga-me: Use uma chamada para completar o &quot;ciclo de monitoramento&quot; <a class="header-anchor" href="#siga-me-use-uma-chamada-para-completar-o-ciclo-de-monitoramento" aria-label="Permalink to &quot;Siga-me: Use uma chamada para completar o &quot;ciclo de monitoramento&quot;&quot;">​</a></h2><h3 id="passo-1-primeiro-crie-uma-solicitacao-que-voce-tem-certeza-que-aparecera" tabindex="-1">Passo 1: Primeiro, crie uma solicitação que &quot;você tem certeza que aparecerá&quot; <a class="header-anchor" href="#passo-1-primeiro-crie-uma-solicitacao-que-voce-tem-certeza-que-aparecera" aria-label="Permalink to &quot;Passo 1: Primeiro, crie uma solicitação que &quot;você tem certeza que aparecerá&quot;&quot;">​</a></h3><p><strong>Por que</strong> O Proxy Monitor só registra solicitações recebidas pelo serviço de proxy reverso. Primeiro use a solicitação mais simples para verificar se há registro, depois fale de filtragem e detalhes.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-eMO23" id="tab-lrGxQtM" checked><label data-title="macOS/Linux" for="tab-lrGxQtM">macOS/Linux</label><input type="radio" name="group-eMO23" id="tab-lDkWQup"><label data-title="Windows" for="tab-lDkWQup">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) Verificação de vivacidade (endpoint que certamente existe)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) Solicite models novamente (se você ativou autenticação, lembre-se de adicionar header)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 1) Verificação de vivacidade (endpoint que certamente existe)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/healthz&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 2) Solicite models novamente (se você ativou autenticação, lembre-se de adicionar header)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">curl </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;http://127.0.0.1:PORT/v1/models&quot;</span></span></code></pre></div></div></div><p><strong>Você deve ver</strong>: O terminal retorna <code>{&quot;status&quot;:&quot;ok&quot;}</code> (ou JSON similar), e a resposta de <code>/v1/models</code> (sucesso ou 401 está ok).</p><h3 id="passo-2-abra-a-pagina-monitor-e-confirme-o-status-de-gravacao" tabindex="-1">Passo 2: Abra a página Monitor e confirme o &quot;status de gravação&quot; <a class="header-anchor" href="#passo-2-abra-a-pagina-monitor-e-confirme-o-status-de-gravacao" aria-label="Permalink to &quot;Passo 2: Abra a página Monitor e confirme o &quot;status de gravação&quot;&quot;">​</a></h3><p><strong>Por que</strong> O Proxy Monitor tem interruptor &quot;gravar/pausar&quot;. Você precisa primeiro confirmar o estado atual, caso contrário você pode estar solicitando o tempo todo, mas a lista estará sempre vazia.</p><p>Nas Antigravity Tools, abra o <strong>Painel de Monitoramento de API</strong> na barra lateral (rota <code>/monitor</code>).</p><p>Haverá um botão com ponto na parte superior da página:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ● Gravando  [Caixa de busca]  [Atualizar] [Limpar]      │</span></span>
<span class="line"><span>└───────────────────────────────────────────┘</span></span></code></pre></div><p>Se você vê &quot;Pausado&quot;, clique uma vez para mudar para &quot;Gravando&quot;.</p><p><strong>Você deve ver</strong>: O status do botão muda para &quot;Gravando&quot;; registros de solicitação anteriores começam a aparecer na lista.</p><h3 id="passo-3-use-busca-filtragem-rapida-para-localizar-um-registro" tabindex="-1">Passo 3: Use &quot;busca + filtragem rápida&quot; para localizar um registro <a class="header-anchor" href="#passo-3-use-busca-filtragem-rapida-para-localizar-um-registro" aria-label="Permalink to &quot;Passo 3: Use &quot;busca + filtragem rápida&quot; para localizar um registro&quot;">​</a></h3><p><strong>Por que</strong> Na solução de problemas real, geralmente você só lembra um fragmento: há <code>messages</code> no caminho, ou o código de status é <code>401</code>, ou há <code>gemini</code> no nome do modelo. A caixa de busca é projetada para esse tipo de memória.</p><p>A busca do Proxy Monitor usará sua entrada como uma &quot;palavra-chave aproximada&quot;, correspondendo no backend com SQL <code>LIKE</code> nestes campos:</p><ul><li><code>url</code></li><li><code>method</code></li><li><code>model</code></li><li><code>status</code></li><li><code>account_email</code></li></ul><p>Você pode tentar algumas palavras-chave típicas:</p><ul><li><code>healthz</code></li><li><code>models</code></li><li><code>401</code> (se você criou um 401)</li></ul><p>Também pode clicar no botão &quot;filtragem rápida&quot;: <strong>Apenas erros / Chat / Gemini / Claude / Geração de imagem</strong>.</p><p><strong>Você deve ver</strong>: A lista só contém o tipo de solicitação que você esperava.</p><h3 id="passo-4-clique-em-detalhes-para-restaurar-payload-de-solicitacao-payload-de-resposta" tabindex="-1">Passo 4: Clique em detalhes para restaurar &quot;payload de solicitação + payload de resposta&quot; <a class="header-anchor" href="#passo-4-clique-em-detalhes-para-restaurar-payload-de-solicitacao-payload-de-resposta" aria-label="Permalink to &quot;Passo 4: Clique em detalhes para restaurar &quot;payload de solicitação + payload de resposta&quot;&quot;">​</a></h3><p><strong>Por que</strong> A lista é suficiente para responder &quot;o que aconteceu&quot;. Para responder &quot;por que&quot;, geralmente você precisa ver o payload completo de solicitação/resposta.</p><p>Clique em qualquer registro, uma janela de detalhes aparecerá. Você pode focar em verificar:</p><ul><li><code>protocolo</code> (OpenAI/Claude/Gemini)</li><li><code>modelo usado</code> e <code>modelo mapeado</code></li><li><code>conta usada</code></li><li><code>consumo de Token (entrada/saída)</code></li></ul><p>Depois use botões para copiar:</p><ul><li><code>payload de solicitação (Request)</code></li><li><code>payload de resposta (Response)</code></li></ul><p><strong>Você deve ver</strong>: Há dois blocos de JSON (ou texto) na visualização de detalhes; após copiar, você pode colar em tickets/notas para análise.</p><h3 id="passo-5-quando-voce-precisa-recriar-do-zero-limpe-os-logs" tabindex="-1">Passo 5: Quando você precisa &quot;recriar do zero&quot;, limpe os logs <a class="header-anchor" href="#passo-5-quando-voce-precisa-recriar-do-zero-limpe-os-logs" aria-label="Permalink to &quot;Passo 5: Quando você precisa &quot;recriar do zero&quot;, limpe os logs&quot;">​</a></h3><p><strong>Por que</strong> Na solução de problemas, o pior é &quot;dados antigos interferindo no julgamento&quot;. Limpe e recrie uma vez, sucesso/falha ficará muito claro.</p><p>Clique no botão &quot;Limpar&quot; na parte superior, uma caixa de confirmação aparecerá.</p><div class="danger custom-block"><p class="custom-block-title">Esta é uma operação irreversível</p><p>Limpar excluirá todos os registros em <code>proxy_logs.db</code>.</p></div><p><strong>Você deve ver</strong>: Após confirmação, a lista fica vazia, os números estatísticos voltam a 0.</p><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><ul><li>[ ] Você pode ver registros de <code>/healthz</code> ou <code>/v1/models</code> que você acabou de enviar em <code>/monitor</code></li><li>[ ] Você pode filtrar um registro específico usando a caixa de busca (por exemplo, digite <code>healthz</code>)</li><li>[ ] Você pode clicar em um registro para ver payloads de solicitação/resposta e copiá-los</li><li>[ ] Você sabe que limpar logs excluirá todos os registros históricos</li></ul><h2 id="avisos-sobre-armadilhas" tabindex="-1">Avisos sobre armadilhas <a class="header-anchor" href="#avisos-sobre-armadilhas" aria-label="Permalink to &quot;Avisos sobre armadilhas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cenário</th><th>Você pode entender (❌)</th><th>Comportamento real (✓)</th></tr></thead><tbody><tr><td>&quot;Pausado&quot; = nenhum custo de monitoramento</td><td>Acredita que após pausar, solicitações não serão analisadas</td><td>Pausar só afeta &quot;se grava ou não logs do Proxy Monitor&quot;. Mas análise de solicitação/resposta (incluindo análise SSE de dados de streaming) ainda ocorrerá, apenas dados analisados não serão salvos. Token Stats ainda gravará (independentemente do monitor estar ativado).</td></tr><tr><td>Logs binários/grandes ficam vazios</td><td>Acredita que monitoramento quebrou</td><td>Solicitações/respostas binárias mostrarão como <code>[Binary Request Data]</code> / <code>[Binary Response Data]</code>. Corpos de resposta acima de 100MB serão marcados como <code>[Response too large (&gt;100MB)]</code>; corpos de solicitação acima do limite não serão gravados.</td></tr><tr><td>Quer usar Monitor para encontrar &quot;quem iniciou a solicitação&quot;</td><td>Acredita que pode rastrear até o processo do cliente</td><td>O Monitor registra informações na camada HTTP (método/caminho/modelo/conta), não contém &quot;nome do processo solicitante&quot;. Você precisa combinar logs do próprio cliente ou captura de pacotes de rede do sistema para localizar a fonte.</td></tr><tr><td>Dados de Token Stats anormais quando monitor ativado</td><td>Acredita que é erro estatístico</td><td>Quando monitor ativado, Token Stats pode ser gravado duas vezes (uma no início da função de monitoramento, uma ao gravar assincronamente no banco de dados). Este é o comportamento do código-fonte da versão atual.</td></tr></tbody></table><h2 id="exportacao-e-retencao-a-longo-prazo-primeiro-esclareca-os-limites-de-capacidade" tabindex="-1">Exportação e retenção a longo prazo: primeiro esclareça os limites de capacidade <a class="header-anchor" href="#exportacao-e-retencao-a-longo-prazo-primeiro-esclareca-os-limites-de-capacidade" aria-label="Permalink to &quot;Exportação e retenção a longo prazo: primeiro esclareça os limites de capacidade&quot;">​</a></h2><h3 id="_1-o-que-pode-ser-feito-na-gui-atualmente" tabindex="-1">1) O que pode ser feito na GUI atualmente <a class="header-anchor" href="#_1-o-que-pode-ser-feito-na-gui-atualmente" aria-label="Permalink to &quot;1) O que pode ser feito na GUI atualmente&quot;">​</a></h3><p>Na UI do Monitor da versão atual (<code>ProxyMonitor.tsx</code>), você pode:</p><ul><li>Buscar/filtrar/navegar paginado</li><li>Clicar em detalhes para ver e copiar payload</li><li>Limpar todos os logs</li></ul><p>Mas <strong>não há &quot;botão de exportação&quot;</strong> (a fonte não vê nenhuma UI relacionada).</p><h3 id="_2-que-capacidade-de-exportacao-o-backend-ja-tem-adequado-para-desenvolvimento-secundario" tabindex="-1">2) Que capacidade de exportação o backend já tem (adequado para desenvolvimento secundário) <a class="header-anchor" href="#_2-que-capacidade-de-exportacao-o-backend-ja-tem-adequado-para-desenvolvimento-secundario" aria-label="Permalink to &quot;2) Que capacidade de exportação o backend já tem (adequado para desenvolvimento secundário)&quot;">​</a></h3><p>O comando Tauri do backend fornece dois métodos de exportação:</p><ul><li><code>export_proxy_logs(file_path)</code>: exporta &quot;todos os logs&quot; do banco de dados para arquivo JSON</li><li><code>export_proxy_logs_json(file_path, json_data)</code>: grava o array JSON que você passou formatado em arquivo (requer que a entrada seja formato de array)</li></ul><p>Se você quer desenvolver secundariamente a GUI, ou escrever seu próprio script de chamada, pode reutilizar diretamente esses comandos.</p><h3 id="_3-o-export-mais-simples-backup-direto-de-proxy-logs-db" tabindex="-1">3) O &quot;export&quot; mais simples: backup direto de <code>proxy_logs.db</code> <a class="header-anchor" href="#_3-o-export-mais-simples-backup-direto-de-proxy-logs-db" aria-label="Permalink to &quot;3) O &quot;export&quot; mais simples: backup direto de \`proxy_logs.db\`&quot;">​</a></h3><p>Como o Proxy Monitor é essencialmente SQLite, você também pode tratar <code>proxy_logs.db</code> como &quot;pacote de evidências de solução de problemas&quot; e fazer backup junto (por exemplo, junto com <code>token_stats.db</code>). Localização do diretório de dados veja <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/start/first-run-data/">Primeira execução</a></strong>.</p><h2 id="leitura-recomendada" tabindex="-1">Leitura recomendada <a class="header-anchor" href="#leitura-recomendada" aria-label="Permalink to &quot;Leitura recomendada&quot;">​</a></h2><ul><li>Quer entender mapeamento de modelo: <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/advanced/model-router/">Roteamento de modelo: mapeamento personalizado, prioridade de curinga e estratégias predefinidas</a></strong></li><li>Quer solucionar problemas de autenticação: <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/faq/auth-401/">401/Falha de autenticação: auth_mode, compatibilidade de Header e lista de configuração de cliente</a></strong></li><li>Quer combinar Monitor com estatísticas de custo: a próxima seção abordará Token Stats (<code>token_stats.db</code>)</li></ul><h2 id="resumo-desta-aula" tabindex="-1">Resumo desta aula <a class="header-anchor" href="#resumo-desta-aula" aria-label="Permalink to &quot;Resumo desta aula&quot;">​</a></h2><ul><li>O valor do Proxy Monitor é &quot;revisitável&quot;: registra código de status/caminho/protocolo/conta/mapeamento de modelo/uso de Token, e fornece detalhes de solicitação</li><li>Busca e filtragem rápida são pontos de entrada para solução de problemas: primeiro缩小范围, depois clique em detalhes para ver payload</li><li>Limpar logs é irreversível; exportar atualmente tende mais a &quot;capacidade de desenvolvimento secundário&quot; e &quot;arquivo de banco de dados&quot;</li></ul><h2 id="proxima-aula" tabindex="-1">Próxima aula <a class="header-anchor" href="#proxima-aula" aria-label="Permalink to &quot;Próxima aula&quot;">​</a></h2><blockquote><p>Na próxima aula, aprenderemos <strong><a href="/docs/opencodedocs/pt/lbjlaq/Antigravity-Manager/advanced/token-stats/">Token Stats: métricas de perspectiva de custo e interpretação de gráficos</a></strong>, transformando &quot;sensação de caro&quot; em otimização quantificável.</p></blockquote><hr><h2 id="apendice-referencias-de-codigo-fonte" tabindex="-1">Apêndice: Referências de código-fonte <a class="header-anchor" href="#apendice-referencias-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referências de código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver localizações do código-fonte</strong></summary><blockquote><p>Atualizado em: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Número da linha</th></tr></thead><tbody><tr><td>Entrada da página Monitor (montando ProxyMonitor)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Monitor.tsx#L1-L12" target="_blank" rel="noreferrer"><code>src/pages/Monitor.tsx</code></a></td><td>1-12</td></tr><tr><td>UI do Monitor: tabela/filtragem/popup de detalhes</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L13-L713" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>13-713</td></tr><tr><td>UI: ler configuração e sincronizar enable_logging</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L174-L243" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>174-243</td></tr><tr><td>UI: alternar gravação (gravar config + set_proxy_monitor_enabled)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L254-L267" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>254-267</td></tr><tr><td>UI: listener de eventos em tempo real (proxy://request) e desduplicação</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L273-L355" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>273-355</td></tr><tr><td>UI: limpar logs (clear_proxy_logs)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L389-L403" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>389-403</td></tr><tr><td>UI: carregar detalhes únicos (get_proxy_log_detail)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/proxy/ProxyMonitor.tsx#L505-L519" target="_blank" rel="noreferrer"><code>src/components/proxy/ProxyMonitor.tsx</code></a></td><td>505-519</td></tr><tr><td>Middleware de monitoramento: capturar solicitação/resposta, analisar token, gravar monitor</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L13-L337" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>13-337</td></tr><tr><td>ProxyMonitor: interruptor habilitado, gravar DB, enviar evento</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L33-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>33-194</td></tr><tr><td>Servidor montando middleware de monitoramento (layer)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L183-L194" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>183-194</td></tr><tr><td>Comandos Tauri: get/count/filter/detail/clear/export</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/proxy.rs#L180-L314" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/proxy.rs</code></a></td><td>180-314</td></tr><tr><td>SQLite: caminho proxy_logs.db, estrutura de tabela e SQL de filtragem</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L1-L416" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>1-416</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Constantes-chave</strong>:</p><ul><li><code>MAX_REQUEST_LOG_SIZE = 100 * 1024 * 1024</code>: corpo de solicitação máximo que middleware de monitoramento pode ler (falhará se exceder)</li><li><code>MAX_RESPONSE_LOG_SIZE = 100 * 1024 * 1024</code>: corpo de resposta máximo que middleware de monitoramento pode ler (usado para grandes respostas como imagens)</li></ul><p><strong>Funções/comandos-chave</strong>:</p><ul><li><code>monitor_middleware(...)</code>: coletar solicitação e resposta na camada HTTP e chamar <code>monitor.log_request(...)</code></li><li><code>ProxyMonitor::log_request(...)</code>: gravar memória + SQLite, e推送 resumo através de evento <code>proxy://request</code></li><li><code>get_proxy_logs_count_filtered(filter, errors_only)</code> / <code>get_proxy_logs_filtered(...)</code>: filtragem e paginação da página de lista</li><li><code>get_proxy_log_detail(log_id)</code>: carregar corpo completo de request/response de log único</li><li><code>export_proxy_logs(file_path)</code>: exportar todos os logs para arquivo JSON (botão UI não exposto atualmente)</li></ul></details>`,74)])])}const g=a(i,[["render",s]]);export{m as __pageData,g as default};
